// ── NORMALIZE (multi-format — handles RSS, GitHub, Reddit, HN, YouTube, GraphQL) ──
function get(obj, ...keys) {
  for (const k of keys) {
    let v = obj;
    for (const p of k.split('.')) { if (v == null) break; v = v[p]; }
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return null;
}
function normalizeUrl(u) {
  if (!u) return '';
  try { const x = new URL(String(u).trim()); ['utm_source','utm_medium','utm_campaign','ref'].forEach(p => x.searchParams.delete(p)); return x.href; } catch { return String(u).trim(); }
}
function normalizeDate(v) {
  if (!v) return null;
  if (typeof v === 'number') v = v > 9999999999 ? new Date(v) : new Date(v * 1000);
  try { const d = new Date(v); return isNaN(d.getTime()) ? null : d.toISOString(); } catch { return null; }
}
function normalizeTags(t) {
  if (!t) return [];
  const arr = Array.isArray(t) ? t : String(t).split(',');
  return arr.map(s => {
    const n = get(s, 'name') || String(s);
    return String(n).trim().toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,'');
  }).filter(s => s.length > 0 && s.length <= 50).slice(0, 20);
}
function normalizeTitle(raw) {
  const t = get(raw, 'title._', 'title.#text', 'title', 'name', 'tag_name', 'subject');
  return t ? String(t).trim().replace(/\s+/g,' ').slice(0,500) : null;
}
function normalizeContent(raw) {
  const c = get(raw, 'content:encoded', 'content_html', 'content', 'contentSnippet', 'body', 'description', 'selftext', 'text', 'summary');
  return c ? String(c).slice(0, 50000) : null;
}

const out = $input.all().map(item => {
  const raw = item.json;
  const ctx = raw._ctx || {};
  const title = normalizeTitle(raw);
  const url = normalizeUrl(get(raw, 'link', 'url', 'html_url', 'permalink_url', 'canonical_url') || '');
  if (!title || !url) return null;
  return { json: {
    _ctx:         ctx,
    title,
    url,
    source_slug:  ctx.source_slug || get(raw, 'source_slug') || '',
    content_raw:  normalizeContent(raw),
    author:       String(get(raw, 'creator', 'author', 'author.login', 'author.name', 'by', 'user.login', 'user.username') || '').slice(0,200) || null,
    published_at: normalizeDate(get(raw, 'isoDate', 'pubDate', 'published_at', 'created_at', 'updated_at', 'created_utc', 'published', 'createdAt')),
    tags:         normalizeTags(get(raw, 'categories', 'topics', 'tags', 'topics.edges') || []),
    language:     'en',
    category_hint:ctx.category_hint || '',
    external_id:  String(get(raw, 'guid', 'id', 'full_name', 'external_id') || '').slice(0,200) || null,
    metadata:     { source_type: ctx.source_type || 'unknown', guid: get(raw,'guid','id') },
    collected_at: new Date().toISOString(),
  }};
}).filter(Boolean);
console.log(`[NORMALIZE] in=${$input.all().length} out=${out.length}`);
return out;

const REQUIRED = ['title','url','source_slug'];
function validate(item) {
  const errors = [];
  for (const f of REQUIRED) { if (!item[f] || !String(item[f]).trim()) errors.push(f+':required'); }
  if (item.url) { try { new URL(item.url); } catch { errors.push('url:invalid'); } }
  if (!Array.isArray(item.tags)) errors.push('tags:must-be-array');
  if (item.published_at) { const d = new Date(item.published_at); if (isNaN(d)) errors.push('published_at:invalid'); }
  return errors;
}
const valid = [], skipped = [];
for (const item of $input.all()) {
  const e = validate(item.json);
  if (e.length === 0) valid.push(item);
  else { skipped.push(item.json.url || '?'); console.warn('[VALIDATE] rejected:', e.join(','), item.json.url); }
}
console.log(`[VALIDATE] valid=${valid.length} skipped=${skipped.length}`);
return valid;

function hashUrl(url) {
  const s = url.trim().toLowerCase();
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = (h * 16777619) >>> 0; }
  return h.toString(16).padStart(8,'0');
}
function readTime(text) { return !text ? 1 : Math.max(1, Math.round(text.trim().split(/\s+/).length / 200)); }

const enriched = $input.all().map(item => {
  const i = item.json;
  const ctx = i._ctx || {};
  return { json: {
    ...i,
    url_hash:            hashUrl(i.url),
    language:            i.language || 'en',
    fetched_at:          new Date().toISOString(),
    estimated_read_time: readTime(i.content_raw),
    metadata: {
      ...(i.metadata || {}),
      collector_name:    ctx.workflow_name    || 'unknown',
      collector_version: ctx.collector_version|| '1.0.0',
      pipeline_version:  ctx.pipeline_version || '1.0.0',
      source_slug:       ctx.source_slug      || i.source_slug,
    },
  }};
});
console.log(`[ENRICH] enriched=${enriched.length}`);
return enriched;

const response = $('Check Existing Hashes').first().json;
const existing = new Set((response?.data?.results || []).map(r => r.url_hash).filter(Boolean));
const allItems = $('Enrich Items').all();
const seen = new Set();
const newItems = [];
for (const item of allItems) {
  const h = item.json.url_hash;
  if (existing.has(h) || seen.has(h)) { console.log('[DEDUP] skip:', item.json.url); }
  else { newItems.push(item); seen.add(h); }
}
console.log(`[DEDUP] new=${newItems.length} dup=${allItems.length - newItems.length}`);
return newItems;

const src = $('Resolve Source ID').first().json?.data;
const sourceId = src?.id ?? null;
if (!sourceId) console.warn('[STORE] no source_id for slug:', $('Execute Workflow Trigger').first().json._ctx?.source_slug);
return $('Filter Duplicates').all()
  .filter(item => !!sourceId)
  .map(item => {
    const { _ctx, ...rest } = item.json;
    return { json: {
      source_id:            sourceId,
      title:                rest.title,
      url:                  rest.url,
      content_raw:          rest.content_raw,
      author:               rest.author,
      published_at:         rest.published_at,
      tags:                 rest.tags,
      importance_score:     0.5,
      external_id:          rest.external_id,
      category_hint:        rest.category_hint,
      estimated_read_time:  rest.estimated_read_time,
      language:             rest.language,
      raw_payload:          rest,
      normalized_payload:   {
        title: rest.title, url: rest.url, source_slug: rest.source_slug,
        author: rest.author, published_at: rest.published_at, tags: rest.tags,
        language: rest.language, content_raw: rest.content_raw,
      },
      metadata: {
        ...(rest.metadata || {}),
        url_hash: rest.url_hash,
        fetched_at: rest.fetched_at,
      },
    }};
  });

const ctx          = $('Execute Workflow Trigger').first().json._ctx || {};
const fetched      = ($('Normalize Items').all().length + ($('Normalize Items').all().length > 0 ? 0 : 0));
const allRaw       = $('Execute Workflow Trigger').all().length;
const normalized   = $('Normalize Items').all().length;
const validated    = $('Validate Items').all().length;
const deduped      = $('Filter Duplicates').all().length;
const storeRes     = (() => { try { return $('Store Items').all(); } catch { return []; } })();
const stored       = storeRes.filter(r => r.json?.success === true).length;
const storeFailed  = storeRes.filter(r => r.json?.success === false).length;

const report = {
  collector_id:     ctx.collector_id    || ctx.workflow_name || 'unknown',
  collector_name:   ctx.collector_name  || ctx.workflow_name || 'unknown',
  source_slug:      ctx.source_slug     || 'unknown',
  run_id:           ctx.run_id          || 'unknown',
  started_at:       ctx.started_at      || new Date().toISOString(),
  finished_at:      new Date().toISOString(),
  duration_ms:      ctx.started_at ? Date.now() - new Date(ctx.started_at).getTime() : 0,
  status:           storeFailed > 0 ? 'partial' : 'success',
  items_fetched:    allRaw,
  items_validated:  validated,
  items_stored:     stored,
  items_duplicate:  validated - deduped,
  items_skipped:    normalized - validated,
  store_failures:   storeFailed,
  version:          ctx.collector_version || '1.0.0',
};
console.log('[SUMMARY]', JSON.stringify(report));
return [{ json: report }];
